// ============================================
// ХЕЛПЕРИ ДЛЯ РОБОТИ ЗІ СЛОВАМИ
// ============================================

// Отримати слова за рівнем
export const getWordsByLevel = (level) => {
  return words.filter(word => word.level === level);
};

// Отримати слова за категорією
export const getWordsByCategory = (category) => {
  return words.filter(word => word.category === category);
};

// Отримати слова за рівнем і категорією
export const getWordsByLevelAndCategory = (level, category) => {
  return words.filter(word => word.level === level && word.category === category);
};

// Отримати випадкові слова (для вікторини)
export const getRandomWords = (excludeId, count = 3) => {
  const filtered = words.filter(word => word.id !== excludeId);
  const shuffled = filtered.sort(() => 0.5 - Math.random());
  return shuffled.slice(0, count);
};

// Отримати слово за ID
export const getWordById = (id) => {
  return words.find(word => word.id === id);
};

// Отримати всі слова
export const getAllWords = () => words;

// Отримати кількість слів за рівнем
export const getWordCountByLevel = (level) => {
  return words.filter(word => word.level === level).length;
};

// Отримати кількість слів за категорією
export const getWordCountByCategory = (category) => {
  return words.filter(word => word.category === category).length;
};

// Отримати статистику
export const getVocabularyStats = () => {
  const stats = {
    total: words.length,
    byLevel: {},
    byCategory: {},
  };
  
  const levels = ['A1', 'A2', 'B1', 'B2', 'C1', 'C2'];
  levels.forEach(level => {
    stats.byLevel[level] = getWordCountByLevel(level);
  });
  
  const categories = [
    'people', 'home', 'food', 'health', 'education',
    'work', 'money', 'travel', 'nature', 'technology',
    'art', 'science', 'society', 'law', 'sport',
    'media', 'time', 'places', 'materials', 'abstract'
  ];
  categories.forEach(category => {
    stats.byCategory[category] = getWordCountByCategory(category);
  });
  
  return stats;
};

export default {
  words,
  getWordsByLevel,
  getWordsByCategory,
  getWordsByLevelAndCategory,
  getRandomWords,
  getWordById,
  getAllWords,
  getWordCountByLevel,
  getWordCountByCategory,
  getVocabularyStats,
};
